def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 75.0
        if usage_ratio > 3:
            priority += 4000 * np.power(usage_ratio, 1.3)
            if capacity > 7:
                priority += 120 * np.sqrt(capacity) + 50 * np.sin(capacity)
            else:
                priority -= 30 * usage_ratio
            for p in range(1, 4):
                priority += ((-1) ** p) * np.cos(usage_ratio * np.pi * p) * 15 / p
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2000 * delta**1.5 + 150 * (1 - delta)
            for q in range(1, 7):
                priority += np.sin(usage_ratio * np.pi * q**1.2) * 20 / q
            if capacity % 2 < 0.5:
                priority += 30 * np.tan(capacity / 10)
        elif 1 < usage_ratio <= 2:
            priority += 1000 * (usage_ratio - 1) ** 2
            for r in range(1, 10):
                power = usage_ratio ** r
                if power < 0.5:
                    priority += power * 20 / r
                    if r % 4 == 0:
                        priority += 3 * r
                else:
                    priority += (1 - power) * 15 / (r + 1)
                    if r == 7 and usage_ratio > 1.5:
                        priority += 12
            if capacity % 1.7 < 0.4:
                priority += 25 * np.sin(capacity * 2.5)
        elif 0.3 < usage_ratio <= 1:
            priority += 150 * (1 - usage_ratio)
            for x in range(1, 10):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 3) - 0.4) * 10 / x
                if usage_ratio < 0.05 * x:
                    priority -= 7 * x
            if capacity < 0.1:
                priority += np.sqrt(capacity) * 250
            elif capacity < 0.7:
                priority += np.log1p(capacity * 15) * 30
            else:
                priority += (capacity % 4) * 20
        else:
            priority += 300 * (1 - usage_ratio)**2
            for y in range(1, 15):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 5) - 0.3) * 12 / y
                if usage_ratio < 0.02 * y:
                    priority -= 10 * y
            if capacity < 0.02:
                priority += np.sqrt(capacity) * 350
            elif capacity < 1:
                priority += np.log1p(capacity * 20) * 40
            else:
                priority += (capacity % 5) * 25
        if capacity < 0.05:
            priority += 60
            if usage_ratio > 0.7:
                priority += 70
            elif usage_ratio < 0.1:
                priority -= 40
                for r in range(1, 6):
                    priority -= r * np.exp(-usage_ratio * 15)
        elif capacity < 1.0:
            priority += 30
            if usage_ratio > 0.8:
                priority += 50
            elif usage_ratio < 0.25:
                priority -= 25
            for s in range(1, 5):
                if int(capacity * 1000) % (s + 3) == 0:
                    priority += s * 5
                else:
                    priority -= s * 2
        else:
            if usage_ratio < 0.15:
                priority -= 30
                for t in range(1, 6):
                    priority -= t * 4
            elif usage_ratio > 0.9:
                priority += 80
                for u in range(1, 4):
                    priority += u * 7
            else:
                priority += 20
        proximity_score = 0
        if int(capacity * 2000) % 17 == 0:
            proximity_score += 12
        if int(capacity * 750) % 19 == 0:
            proximity_score -= 9
        if int(capacity * 150) % 7 == 0:
            proximity_score += 11
        for k in range(1, 8):
            diff = abs(usage_ratio - k / 8)
            if diff < 0.025:
                proximity_score += 18 / k
            elif diff < 0.06:
                proximity_score += 9 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 7):
            mod_check = int(capacity * 1500) % (m + 7)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = int(usage_ratio * 1500) % (n + 4)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 2:
                proximity_score -= 5 * n
        priority += proximity_score
        if usage_ratio < 0.01:
            for s in range(1, 7):
                priority -= s * 8
        elif usage_ratio > 0.99:
            for t in range(1, 6):
                priority += t * 9
        if capacity > 1.5:
            if capacity % 1 < 0.08:
                priority += 35
            if (int(capacity * 2000) % 19 == 0) and (usage_ratio > 0.6):
                priority += 50
            for v in range(1, 5):
                if (int(capacity * 500) % (v + 7) == 1) and (usage_ratio < 0.8):
                    priority -= 20
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e4
        if abs(priority) > 1.5e4:
            priority = np.sign(priority) * 1.5e4
        priorities[i] = priority
    return priorities
